import unittest
from dataclasses import dataclass
from typing import Dict, List, Final

# --- Custom Exceptions ---

class InventoryError(Exception):
    """Base class for inventory exceptions."""
    pass

class ItemNotFoundError(InventoryError):
    """Raised when an item does not exist in the inventory."""
    pass

class InsufficientStockError(InventoryError):
    """Raised when an operation would result in negative stock."""
    pass

class DuplicateItemError(InventoryError):
    """Raised when attempting to add an item with an existing ID."""
    pass

# --- Data Model ---

@dataclass
class Item:
    """Represents an inventory item."""
    id: str
    name: str
    quantity: int

    def __post_init__(self) -> None:
        if not isinstance(self.id, str) or not self.id.strip():
            raise ValueError("Item ID must be a non-empty string.")
        if not isinstance(self.quantity, int) or self.quantity < 0:
            raise ValueError("Quantity must be a non-negative integer.")

# --- Manager Class ---

class InventoryManager:
    """Manages collection of items and stock operations."""

    LOW_STOCK_THRESHOLD: Final[int] = 5

    def __init__(self) -> None:
        self._items: Dict[str, Item] = {}

    def add_item(self, item: Item) -> None:
        """Adds a new item to the inventory."""
        if item.id in self._items:
            raise DuplicateItemError(f"Item with ID '{item.id}' already exists.")
        self._items[item.id] = item

    def update_stock(self, item_id: str, delta: int) -> None:
        """Updates stock levels by a delta (positive or negative)."""
        if item_id not in self._items:
            raise ItemNotFoundError(f"Item '{item_id}' not found.")

        item = self._items[item_id]
        new_quantity = item.quantity + delta

        if new_quantity < 0:
            raise InsufficientStockError(f"Operation failed: Resulting stock for '{item_id}' would be negative.")

        item.quantity = new_quantity

    def get_low_stock_alerts(self) -> List[Item]:
        """Returns list of items with quantity below threshold."""
        return [item for item in self._items.values() if item.quantity < self.LOW_STOCK_THRESHOLD]

# --- Unit Tests ---

class TestInventoryManager(unittest.TestCase):
    def setUp(self) -> None:
        self.manager = InventoryManager()

    def test_add_item_success(self) -> None:
        item = Item("A1", "Widget", 10)
        self.manager.add_item(item)
        self.assertEqual(self.manager._items["A1"], item)

    def test_duplicate_item_raises_error(self) -> None:
        self.manager.add_item(Item("A1", "Widget", 10))
        with self.assertRaises(DuplicateItemError):
            self.manager.add_item(Item("A1", "Duplicate", 5))

    def test_update_stock_logic(self) -> None:
        self.manager.add_item(Item("A1", "Widget", 10))
        self.manager.update_stock("A1", -5)
        self.assertEqual(self.manager._items["A1"].quantity, 5)
        self.manager.update_stock("A1", 2)
        self.assertEqual(self.manager._items["A1"].quantity, 7)

    def test_insufficient_stock_raises_error(self) -> None:
        self.manager.add_item(Item("A1", "Widget", 2))
        with self.assertRaises(InsufficientStockError):
            self.manager.update_stock("A1", -3)

    def test_low_stock_alert_threshold(self) -> None:
        self.manager.add_item(Item("A1", "Low", 3))
        self.manager.add_item(Item("A2", "Healthy", 10))
        alerts = self.manager.get_low_stock_alerts()
        self.assertEqual(len(alerts), 1)
        self.assertEqual(alerts[0].id, "A1")

if __name__ == "__main__":
    unittest.main()
